(self.webpackChunk=self.webpackChunk||[]).push([[646],{4361:(n,s,a)=>{"use strict";a.r(s),a.d(s,{data:()=>e});const e={key:"v-1e774ea2",path:"/docker/docker-app.html",title:"Docker 常规应用",lang:"en-US",frontmatter:{title:"Docker 常规应用"},excerpt:"",headers:[{level:2,title:"基于 Docker 安装 GitLab Runner",slug:"基于-docker-安装-gitlab-runner",children:[{level:3,title:"环境准备",slug:"环境准备",children:[]},{level:3,title:"daemon.json",slug:"daemon-json",children:[]},{level:3,title:"Dockerfile",slug:"dockerfile",children:[]},{level:3,title:"docker-compose.yml",slug:"docker-compose-yml",children:[]},{level:3,title:"注册 Runner",slug:"注册-runner",children:[]},{level:3,title:"使用 Runner",slug:"使用-runner",children:[]},{level:3,title:"其它命令",slug:"其它命令",children:[]},{level:3,title:"Dockerfile示例",slug:"dockerfile示例",children:[]}]},{level:2,title:"基于 Docker 安装 Jenkins",slug:"基于-docker-安装-jenkins",children:[{level:3,title:"docker-compose",slug:"docker-compose",children:[]},{level:3,title:"解锁 Jenkins",slug:"解锁-jenkins",children:[]},{level:3,title:"使用自定义插件的方式安装",slug:"使用自定义插件的方式安装",children:[]},{level:3,title:"安装成功效果图",slug:"安装成功效果图",children:[]},{level:3,title:"附：Jenkins 手动安装插件",slug:"附-jenkins-手动安装插件",children:[]},{level:3,title:"重启 Jenkins",slug:"重启-jenkins",children:[]}]}],filePathRelative:"docker/docker-app.md",git:{updatedTime:1626154667e3,contributors:[]}}},6700:(n,s,a)=>{"use strict";a.r(s),a.d(s,{default:()=>r});const e=(0,a(6252).uE)('<h2 id="基于-docker-安装-gitlab-runner" tabindex="-1"><a class="header-anchor" href="#基于-docker-安装-gitlab-runner" aria-hidden="true">#</a> 基于 Docker 安装 GitLab Runner</h2><h3 id="环境准备" tabindex="-1"><a class="header-anchor" href="#环境准备" aria-hidden="true">#</a> 环境准备</h3><ul><li>创建工作目录 /usr/local/docker/runner</li><li>创建构建目录 /usr/local/docker/runner/environment</li><li>下载 jdk-8u152-linux-x64.tar.gz 并复制到 /usr/local/docker/runner/environment</li><li>下载 apache-maven-3.5.3-bin.tar.gz 并复制到 /usr/local/docker/runner/environment</li></ul><h3 id="daemon-json" tabindex="-1"><a class="header-anchor" href="#daemon-json" aria-hidden="true">#</a> daemon.json</h3><p>在 /usr/local/docker/runner/environment 目录下创建 daemon.json，用于配置加速器和仓库地址</p><div class="language-json ext-json line-numbers-mode"><pre class="language-json"><code><span class="token punctuation">{</span>\n  <span class="token property">&quot;registry-mirrors&quot;</span><span class="token operator">:</span> <span class="token punctuation">[</span>\n    <span class="token string">&quot;https://registry.docker-cn.com&quot;</span>\n  <span class="token punctuation">]</span><span class="token punctuation">,</span>\n  <span class="token property">&quot;insecure-registries&quot;</span><span class="token operator">:</span> <span class="token punctuation">[</span>\n    <span class="token string">&quot;192.168.10.133:5000&quot;</span>\n  <span class="token punctuation">]</span>\n<span class="token punctuation">}</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><h3 id="dockerfile" tabindex="-1"><a class="header-anchor" href="#dockerfile" aria-hidden="true">#</a> Dockerfile</h3><p>在 /usr/local/docker/runner/environment 目录下创建 Dockerfile</p><div class="language-docker ext-docker line-numbers-mode"><pre class="language-docker"><code><span class="token instruction"><span class="token keyword">FROM</span> gitlab/gitlab-runner</span>\n<span class="token instruction"><span class="token keyword">MAINTAINER</span> maodou38 &lt;maodoulove19950815@vip.qq.com&gt;</span>\n<span class="token comment"># 修改软件源</span>\n<span class="token instruction"><span class="token keyword">RUN</span> echo <span class="token string">&#39;deb http://mirrors.aliyun.com/ubuntu/ xenial main restricted universe multiverse&#39;</span> &gt; /etc/apt/sources.list &amp;&amp; <span class="token operator">\\</span>\n    echo <span class="token string">&#39;deb http://mirrors.aliyun.com/ubuntu/ xenial-security main restricted universe multiverse&#39;</span> &gt;&gt; /etc/apt/sources.list &amp;&amp; <span class="token operator">\\</span>\n    echo <span class="token string">&#39;deb http://mirrors.aliyun.com/ubuntu/ xenial-updates main restricted universe multiverse&#39;</span> &gt;&gt; /etc/apt/sources.list &amp;&amp; <span class="token operator">\\</span>\n    echo <span class="token string">&#39;deb http://mirrors.aliyun.com/ubuntu/ xenial-backports main restricted universe multiverse&#39;</span> &gt;&gt; /etc/apt/sources.list &amp;&amp; <span class="token operator">\\</span>\n    apt-get update -y &amp;&amp; <span class="token operator">\\</span>\n    apt-get clean</span>\n\n<span class="token comment"># 安装 Docker</span>\n<span class="token instruction"><span class="token keyword">RUN</span> apt-get -y install apt-transport-https ca-certificates curl software-properties-common &amp;&amp; <span class="token operator">\\</span>\n    curl -fsSL http://mirrors.aliyun.com/docker-ce/linux/ubuntu/gpg | apt-key add - &amp;&amp; <span class="token operator">\\</span>\n    add-apt-repository <span class="token string">&quot;deb [arch=amd64] http://mirrors.aliyun.com/docker-ce/linux/ubuntu $(lsb_release -cs) stable&quot;</span> &amp;&amp; <span class="token operator">\\</span>\n    apt-get update -y &amp;&amp; <span class="token operator">\\</span>\n    apt-get install -y docker-ce</span>\n<span class="token instruction"><span class="token keyword">COPY</span> daemon.json /etc/docker/daemon.json</span>\n\n<span class="token comment"># 安装 Docker Compose</span>\n<span class="token instruction"><span class="token keyword">WORKDIR</span> /usr/local/bin</span>\n<span class="token instruction"><span class="token keyword">RUN</span> wget https://raw.githubusercontent.com/topsale/resources/master/docker/docker-compose</span>\n<span class="token instruction"><span class="token keyword">RUN</span> chmod +x docker-compose</span>\n\n<span class="token comment"># 安装 Java</span>\n<span class="token instruction"><span class="token keyword">RUN</span> mkdir -p /usr/local/java</span>\n<span class="token instruction"><span class="token keyword">WORKDIR</span> /usr/local/java</span>\n<span class="token instruction"><span class="token keyword">COPY</span> jdk-8u152-linux-x64.tar.gz /usr/local/java</span>\n<span class="token instruction"><span class="token keyword">RUN</span> tar -zxvf jdk-8u152-linux-x64.tar.gz &amp;&amp; <span class="token operator">\\</span>\n    rm -fr jdk-8u152-linux-x64.tar.gz</span>\n\n<span class="token comment"># 安装 Maven</span>\n<span class="token instruction"><span class="token keyword">RUN</span> mkdir -p /usr/local/maven</span>\n<span class="token instruction"><span class="token keyword">WORKDIR</span> /usr/local/maven</span>\n<span class="token comment"># RUN wget https://raw.githubusercontent.com/topsale/resources/master/maven/apache-maven-3.5.3-bin.tar.gz</span>\n<span class="token instruction"><span class="token keyword">COPY</span> apache-maven-3.5.3-bin.tar.gz /usr/local/maven</span>\n<span class="token instruction"><span class="token keyword">RUN</span> tar -zxvf apache-maven-3.5.3-bin.tar.gz &amp;&amp; <span class="token operator">\\</span>\n    rm -fr apache-maven-3.5.3-bin.tar.gz</span>\n<span class="token comment"># COPY settings.xml /usr/local/maven/apache-maven-3.5.3/conf/settings.xml</span>\n\n<span class="token comment"># 配置环境变量</span>\n<span class="token instruction"><span class="token keyword">ENV</span> JAVA_HOME /usr/local/java/jdk1.8.0_152</span>\n<span class="token instruction"><span class="token keyword">ENV</span> MAVEN_HOME /usr/local/maven/apache-maven-3.5.3</span>\n<span class="token instruction"><span class="token keyword">ENV</span> PATH <span class="token variable">$PATH</span>:<span class="token variable">$JAVA_HOME</span>/bin:<span class="token variable">$MAVEN_HOME</span>/bin</span>\n\n<span class="token instruction"><span class="token keyword">WORKDIR</span> /</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br><span class="line-number">22</span><br><span class="line-number">23</span><br><span class="line-number">24</span><br><span class="line-number">25</span><br><span class="line-number">26</span><br><span class="line-number">27</span><br><span class="line-number">28</span><br><span class="line-number">29</span><br><span class="line-number">30</span><br><span class="line-number">31</span><br><span class="line-number">32</span><br><span class="line-number">33</span><br><span class="line-number">34</span><br><span class="line-number">35</span><br><span class="line-number">36</span><br><span class="line-number">37</span><br><span class="line-number">38</span><br><span class="line-number">39</span><br><span class="line-number">40</span><br><span class="line-number">41</span><br><span class="line-number">42</span><br><span class="line-number">43</span><br><span class="line-number">44</span><br><span class="line-number">45</span><br></div></div><h3 id="docker-compose-yml" tabindex="-1"><a class="header-anchor" href="#docker-compose-yml" aria-hidden="true">#</a> docker-compose.yml</h3><p>在 /usr/local/docker/runner 目录下创建 docker-compose.yml</p><div class="language-docker ext-docker line-numbers-mode"><pre class="language-docker"><code>version: &#39;3.1&#39;\nservices:\n  gitlab-runner:\n    build: environment\n    restart: always\n    container_name: gitlab-runner\n    privileged: true\n    volumes:\n      - ./config:/etc/gitlab-runner\n      - /var/run/docker.sock:/var/run/docker.sock\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br></div></div><h3 id="注册-runner" tabindex="-1"><a class="header-anchor" href="#注册-runner" aria-hidden="true">#</a> 注册 Runner</h3><div class="language-docker ext-docker line-numbers-mode"><pre class="language-docker"><code>docker exec -it gitlab-runner gitlab-runner register\n\n<span class="token comment"># 输入 GitLab 地址</span>\nPlease enter the gitlab-ci coordinator URL (e.g. https://gitlab.com/):\nhttp://192.168.10.132/\n\n<span class="token comment"># 输入 GitLab Token</span>\nPlease enter the gitlab-ci token for this runner:\n1Lxq_f1NRfCfeNbE5WRh\n\n<span class="token comment"># 输入 Runner 的说明</span>\nPlease enter the gitlab-ci description for this runner:\n可以为空\n\n<span class="token comment"># 设置 Tag，可以用于指定在构建规定的 tag 时触发 ci</span>\nPlease enter the gitlab-ci tags for this runner (comma separated):\ndeploy\n\n<span class="token comment"># 这里选择 true ，可以用于代码上传后直接执行</span>\nWhether to run untagged builds [true/false]:\ntrue\n\n<span class="token comment"># 这里选择 false，可以直接回车，默认为 false</span>\nWhether to lock Runner to current project [true/false]:\nfalse\n\n<span class="token comment"># 选择 runner 执行器，这里我们选择的是 shell</span>\nPlease enter the executor: virtualbox, docker+machine, parallels, shell, ssh, docker-ssh+machine, kubernetes, docker, docker-ssh:\n<span class="token instruction"><span class="token keyword">shell</span></span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br><span class="line-number">22</span><br><span class="line-number">23</span><br><span class="line-number">24</span><br><span class="line-number">25</span><br><span class="line-number">26</span><br><span class="line-number">27</span><br><span class="line-number">28</span><br><span class="line-number">29</span><br></div></div><h3 id="使用-runner" tabindex="-1"><a class="header-anchor" href="#使用-runner" aria-hidden="true">#</a> 使用 Runner</h3><ul><li><p>GitLab CI 地址与令牌参数 项目 –&gt; 设置 –&gt; CI/CD –&gt; Runner 设置 <img src="/docker/docker-app/gitlab-runner.png" alt=""></p></li><li><p>.gitlab-ci.yml<br> 在项目工程下编写 .gitlab-ci.yml 配置文件：</p></li></ul><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>stages:\n  - install_deps\n  - test\n  - build\n  - deploy_test\n  - deploy_production\n\ncache:\n  key: ${CI_BUILD_REF_NAME}\n  paths:\n    - node_modules/\n    - dist/\n\n# 安装依赖\ninstall_deps:\n  stage: install_deps\n  only:\n    - develop\n    - master\n  script:\n    - npm install\n\n# 运行测试用例\ntest:\n  stage: test\n  only:\n    - develop\n    - master\n  script:\n    - npm run test\n\n# 编译\nbuild:\n  stage: build\n  only:\n    - develop\n    - master\n  script:\n    - npm run clean\n    - npm run build:client\n    - npm run build:server\n\n# 部署测试服务器\ndeploy_test:\n  stage: deploy_test\n  only:\n    - develop\n  script:\n    - pm2 delete app || true\n    - pm2 start app.js --name app\n\n# 部署生产服务器\ndeploy_production:\n  stage: deploy_production\n  only:\n    - master\n  script:\n    - bash scripts/deploy/deploy.sh\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br><span class="line-number">22</span><br><span class="line-number">23</span><br><span class="line-number">24</span><br><span class="line-number">25</span><br><span class="line-number">26</span><br><span class="line-number">27</span><br><span class="line-number">28</span><br><span class="line-number">29</span><br><span class="line-number">30</span><br><span class="line-number">31</span><br><span class="line-number">32</span><br><span class="line-number">33</span><br><span class="line-number">34</span><br><span class="line-number">35</span><br><span class="line-number">36</span><br><span class="line-number">37</span><br><span class="line-number">38</span><br><span class="line-number">39</span><br><span class="line-number">40</span><br><span class="line-number">41</span><br><span class="line-number">42</span><br><span class="line-number">43</span><br><span class="line-number">44</span><br><span class="line-number">45</span><br><span class="line-number">46</span><br><span class="line-number">47</span><br><span class="line-number">48</span><br><span class="line-number">49</span><br><span class="line-number">50</span><br><span class="line-number">51</span><br><span class="line-number">52</span><br><span class="line-number">53</span><br><span class="line-number">54</span><br><span class="line-number">55</span><br><span class="line-number">56</span><br><span class="line-number">57</span><br><span class="line-number">58</span><br></div></div><p>上面的配置把一次 Pipeline 分成五个阶段：</p><ul><li>安装依赖(install_deps)</li><li>运行测试(test)</li><li>编译(build)</li><li>部署测试服务器(deploy_test)</li><li>部署生产服务器(deploy_production)</li></ul><p>注意： 设置 Job.only 后，只有当 develop 分支和 master 分支有提交的时候才会触发相关的 Jobs。 节点说明：</p><ul><li>stages：定义构建阶段，这里只有一个阶段 deploy</li><li>deploy：构建阶段 deploy 的详细配置也就是任务配置</li><li>script：需要执行的 shell 脚本</li><li>only：这里的 master 指在提交到 master 时执行</li><li>tags：与注册 runner 时的 tag 匹配</li></ul><h3 id="其它命令" tabindex="-1"><a class="header-anchor" href="#其它命令" aria-hidden="true">#</a> 其它命令</h3><ul><li>删除注册信息 <code>gitlab-ci-multi-runner unregister --name &quot;名称&quot;</code></li><li>查看注册列表 <code>gitlab-ci-multi-runner list</code></li></ul><h3 id="dockerfile示例" tabindex="-1"><a class="header-anchor" href="#dockerfile示例" aria-hidden="true">#</a> Dockerfile示例</h3><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>    FROM openjdk:8-jre\n\nMAINTAINER maodou38 &lt;maodoulove19950815@vip.qq.com&gt;\n\nENV APP_VERSION 1.0.0-SNAPSHOT\nENV DOCKERIZE_VERSION v0.6.1\nRUN wget https://github.com/jwilder/dockerize/releases/download/$DOCKERIZE_VERSION/dockerize-linux-amd64-$DOCKERIZE_VERSION.tar.gz \\\n    &amp;&amp; tar -C /usr/local/bin -xzvf dockerize-linux-amd64-$DOCKERIZE_VERSION.tar.gz \\\n    &amp;&amp; rm dockerize-linux-amd64-$DOCKERIZE_VERSION.tar.gz\n\nRUN mkdir /app\n\nCOPY myshop-service-user-provider-$APP_VERSION.jar /app/app.jar\nENTRYPOINT [&quot;dockerize&quot;, &quot;-timeout&quot;, &quot;5m&quot;, &quot;-wait&quot;, &quot;tcp://192.168.10.131:3306&quot;, &quot;java&quot;, &quot;-Djava.security.egd=file:/dev/./urandom&quot;, &quot;-jar&quot;, &quot;/app/app.jar&quot;]\n\nEXPOSE 8501\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br></div></div><p><span style="color:#F00;"> DOCKERIZE是一个监听插件，监听依赖服务是否启动</span></p><h2 id="基于-docker-安装-jenkins" tabindex="-1"><a class="header-anchor" href="#基于-docker-安装-jenkins" aria-hidden="true">#</a> 基于 Docker 安装 Jenkins</h2><h3 id="docker-compose" tabindex="-1"><a class="header-anchor" href="#docker-compose" aria-hidden="true">#</a> docker-compose</h3><p>Jenkins 是一个简单易用的持续集成软件平台，我们依然采用 Docker 的方式部署，docker-compose.yml 配置文件如下：</p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>version: &#39;3.1&#39;\nservices:\n  jenkins:\n    restart: always\n    image: jenkinsci/jenkins\n    container_name: jenkins\n    ports:\n      # 发布端口\n      - 8080:8080\n      # 基于 JNLP 的 Jenkins 代理通过 TCP 端口 50000 与 Jenkins master 进行通信\n      - 50000:50000\n    environment:\n      TZ: Asia/Shanghai\n    volumes:\n      - ./data:/var/jenkins_home\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br></div></div><p>安装过程中会出现 Docker 数据卷 权限问题，用以下命令解决：</p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>chown -R 1000 /usr/local/docker/jenkins/data\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br></div></div><h3 id="解锁-jenkins" tabindex="-1"><a class="header-anchor" href="#解锁-jenkins" aria-hidden="true">#</a> 解锁 Jenkins</h3><p>Jenkins 第一次启动时需要输入一个初始密码用以解锁安装流程，使用 docker logs jenkins 即可方便的查看到初始密码 <img src="/docker/docker-app/jenkins-unlock.png" alt=""><img src="/docker/docker-app/jenkins-pass.png" alt=""> 注意： 安装时可能会因为网速等原因导致安装时间比较长，请大家耐心等待。如果长时间停留在安装页没反应，请尝试使用 F5 刷新一下。</p><h3 id="使用自定义插件的方式安装" tabindex="-1"><a class="header-anchor" href="#使用自定义插件的方式安装" aria-hidden="true">#</a> 使用自定义插件的方式安装</h3><p>插件是 Jenkins 的核心，其丰富的插件（截止到 2018.10.29 共有 77350 个插件）可以满足不同人群的不同需求</p><p>插件地址：https://plugins.jenkins.io/</p><p>注意： 除了默认勾选的插件外，一定要勾选 Publish over SSH 插件，这是我们实现持续交付的重点插件。</p><p><strong>开始安装了，根据网络情况，安装时间可能会比较长，请耐心等待</strong></p><p><strong>很多插件装不上怎么办？不要慌，记住这些插件的名字，咱们稍后可以手动安装</strong></p><h3 id="安装成功效果图" tabindex="-1"><a class="header-anchor" href="#安装成功效果图" aria-hidden="true">#</a> 安装成功效果图</h3><p>创建管理员 <img src="/docker/docker-app/jenkins-install-success.png" alt=""></p><p>安装完成，进入首页</p><h3 id="附-jenkins-手动安装插件" tabindex="-1"><a class="header-anchor" href="#附-jenkins-手动安装插件" aria-hidden="true">#</a> 附：Jenkins 手动安装插件</h3><ul><li>使用插件管理器安装 Manage Jenkins -&gt; Manage Plugins -&gt; Avaliable</li></ul><p>过滤出想要安装的插件，然后点击 Download now and install after restart</p><ul><li>手动上传 .hpi 文件 点击进入插件中心</li></ul><p>点击 Archives</p><p>下载需要的版本</p><p>在插件管理器中选择 Advanced</p><p>选择上传即可 <img src="/docker/docker-app/jenkins-upload.png" alt=""></p><h3 id="重启-jenkins" tabindex="-1"><a class="header-anchor" href="#重启-jenkins" aria-hidden="true">#</a> 重启 Jenkins</h3><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>docker-compose down\ndocker-compose up -d\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>注意： 请留意需要下载插件的警告信息，如果不满足安装条件，Jenkins 是会拒绝安装的。如下图： <img src="/docker/docker-app/jenkins-refuse.png" alt=""></p>',54),r={render:function(n,s){return e}}}}]);